import { workflow, node, trigger } from '@n8n/workflow-sdk';

const manual_Trigger = trigger({
  type: 'n8n-nodes-base.manualTrigger',
  version: 1,
  config: { name: 'Manual Trigger' }
});

const status_Marker = node({
  type: 'n8n-nodes-base.set',
  version: 3.4,
  config: { name: 'Status Marker', parameters: { assignments: { assignments: [{ id: 'status-assignment', name: 'status', value: 'denied edit should not apply', type: 'string' }] }, options: {} } }
});

const wf = workflow('cK6nyU9IZfas3ZKe', 'INS-171 Deny Edit Target');

export default wf
  .add(manual_Trigger)
  .to(status_Marker)

